+using Microsoft.AspNetCore.Http;
+using Microsoft.AspNetCore.Mvc;
+using Microsoft.AspNetCore.Mvc.Filters;
+using SharedKernel.Domain.Common;
+
+namespace SharedKernel.Contracts.Api.Filters;
+
+/// <summary>
+///     A unified filter that intercepts both MVC and Minimal API/Wolverine HTTP endpoint results.
+///     It appends pagination HTTP headers if the underlying response body implements <see cref="IPagedResponse" />.
+///
+///     Note: ASP.NET Core has two separate pipelines for returning HTTP responses.
+///     <see cref="IAsyncResultFilter"/> handles classic MVC controllers.
+///     <see cref="IEndpointFilter"/> handles Minimal APIs and Wolverine.
+/// </summary>
+public class PaginationFilter : IAsyncResultFilter, IEndpointFilter
+{
+    // ----- MVC Pipeline (Controllers) -----
+    public async Task OnResultExecutionAsync(
+        ResultExecutingContext context,
+        ResultExecutionDelegate next
+    )
+    {
+        if (context.Result is ObjectResult { Value: IPagedResponse pagedResponse })
+        {
+            PaginationHeaderHelper.AppendLinkHeader(context.HttpContext.Response, pagedResponse);
+        }
+
+        await next();
+    }
+
+    // ----- Minimal API / Wolverine Pipeline -----
+    public async ValueTask<object?> InvokeAsync(
+        EndpointFilterInvocationContext context,
+        EndpointFilterDelegate next
+    )
+    {
+        var result = await next(context);
+
+        if (result is IValueHttpResult { Value: IPagedResponse pagedResponse })
+        {
+            PaginationHeaderHelper.AppendLinkHeader(context.HttpContext.Response, pagedResponse);
+        }
+
+        return result;

body:
![high](https://www.gstatic.com/codereviewagent/high-priority.svg)

The current implementation of `InvokeAsync` only appends headers if the result implements `IValueHttpResult` (e.g., from `TypedResults.Ok()`). However, in Minimal APIs and Wolverine, handlers often return the domain object (like `PagedResponse<T>`) directly. In such cases, the filter will skip the header generation because the result object itself implements `IPagedResponse` but not `IValueHttpResult`. 

Additionally, the use of `var` for the `result` object violates the explicit typing rule in the style guide.

```c#
        object? result = await next(context);

        IPagedResponse? pagedResponse = result switch
        {
            IPagedResponse p => p,
            IValueHttpResult { Value: IPagedResponse p } => p,
            _ => null
        };

        if (pagedResponse is not null)
        {
            PaginationHeaderHelper.AppendLinkHeader(context.HttpContext.Response, pagedResponse);
        }

        return result;
```

